      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  f.request('GetDefaultValue', 'SetDefaultValue', ['tk']);
  var a = ['tk'];
  if (!f._extensions) f.request('GetDefaultValue', 'SetDefaultValue', a);
    else setReferenceValue(f, a);
  if (!f.getItemValue('date_open')) f.setItemValue('date_open', new Date());
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      f.grid._hiddenFields = [{Fields: 'ps_no_nt, ps_co_nt, ma_nt, ty_gia', Value: (f.getItemValue('mau_bc') == '10')}];
      var gr = f.getItemValue('group');
      f.grid._hiddenForms = [{Form: [0, 1], Value: (gr == '0')}, {Form: [2, 3], Value: (gr == '1')}];
      f.grid._alterTitle = [null, [['%s1', f.getItemValue('tk'), true], ['%d1', f.getItem('date_from').value, true], ['%d2', f.getItem('date_to').value, true]]];
      remove$GridReport$Filter(f.grid);
      break;
    case 'SetDefaultValue':
      f.setItemControlBehavior('ten_tk%l', result[0].Value, null, true);
      if (result[0].Value == '') f.setItemValue('tk', '');
      break;
    default:
      break;
  }
}
function setReferenceValue(f, a) {
  for (var i = 0; i < a.length; i++) {
    var r = $func.findField(a[i], f._fields).ItemReference;
    f.setItemValue(r, $func.findMemvar(r, f._extensions).NewValue);
  }
}
/* </flatten> */







declare @c0 nvarchar(1024)
select @c0 = ten_tk%l from dmtk where tk = @tk
select isnull(@c0, '') as c0
return





